+int main(int argc, char * argv[])
+{
+  auto args = rclcpp::init_and_remove_ros_arguments(argc, argv);
+  auto options = rclcpp::NodeOptions{};
+
+  if (args.size() < 3) {
+    RCLCPP_ERROR(
